    for(int i=0;i<4;i++) {
        int nx=x+dx[i];
        int ny=y+dy[i];
        if(nx>0&&nx<=n&&ny>0&&ny<=m&&mp[nx][ny]==1
                               &&vis[nx][ny]==0){
            vis[nx][ny]=1; //标记已访问
            dfs(nx, ny);
        }
    }
}
