void bfs(){
    node a={1,1};  q.push(a);  vis[1][1]=1;
    while(q.empty()!=1){//队列不为空
        node f=q.front();
        if(mp[f.x][f.y]=='@'){
            cout<<"YES";
            return;
        }
        for(int i=0;i<4;i++){
            int nx=f.x+dx[i],ny=f.y+dy[i];
            if((nx>=1&&nx<=n&&ny>=1&&ny<=n)&&vis[nx][ny]==0&&mp[nx][ny]!='#'){
                vis[nx][ny]=1;//标记  
                node r={nx,ny};
                q.push(r);//新点入队
            }
        }
        q.pop();//队首出队
    }
    cout<<"NO";
}
